module top_module(
    X ,
    obf_A1,
    A2,
    A3,
    B1,
    B2
);output X ;
    input  obf_A1;
    input  A2;
    input  A3;
    input  B1;
    input  B2;

    assign X = (obf_A1 & A2 & ~A3) ? 0 :
               (~obf_A1 & ~A2) ? 1 :
               (obf_A1 & ~A2) ? B1 :
               (~obf_A1 & A2) ? B2 :
               1'b1;

endmodule
